# Module: pricing.py (the code being tested)
def calculate_discount(price: float, discount_pct: float) -> float:
    # Validates and calculates discounted price
    if discount_pct < 0 or discount_pct > 100:
        raise ValueError("Discount must be 0-100")  # Guard clause
    if price < 0:
        raise ValueError("Price cannot be negative")
    return price * (1 - discount_pct / 100)

# Module: test_pricing.py (the test file — pytest discovers it automatically)
def test_no_discount():
    # Zero percent discount should return the original price
    assert calculate_discount(100, 0) == 100.0

def test_fifty_percent():
    # Half off $80 should be exactly $40
    assert calculate_discount(80, 50) == 40.0

def test_full_discount():
    # 100% discount means the item is free
    assert calculate_discount(50, 100) == 0.0

def test_negative_price():
    # Negative prices should raise an error — not silently return wrong value
    import pytest  # pytest provides advanced assertions
    with pytest.raises(ValueError):  # Expect a ValueError to be raised
        calculate_discount(-10, 20)

def test_invalid_discount():
    # Discount over 100% should not be allowed
    with pytest.raises(ValueError):
        calculate_discount(100, 150)

# Run with: pytest test_pricing.py -v (v = verbose output)
# Expected output: all 5 tests pass (indicated by green dots or PASSED)
